mapper.select:
SELECT COUNT(*)
FROM favorite_deals
WHERE user_id = #{userId}
  AND deal_no = #{dealNo}

mapper.delete:
DELETE FROM favorite_deals
WHERE user_id = #{userId}
  AND deal_no = #{dealNo}

mapper.select:
SELECT deal_no
FROM favorite_deals
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}
